import React, { Component } from "react";
import { Link } from "react-router-dom";
import "./home.css";

const ROLE_TITLES = [
  "Software engineer at Google.",
  "AI product builder.",
  "ML/NLP researcher.",
  "Pianist and violinist.",
];

class Home extends Component {
  constructor(props) {
    super(props);
    this.state = {
      roleIndex: 0,
    };
  }

  componentDidMount() {
    // change role every 3.5 seconds (2s typing + ~1.5s pause)
    this.roleInterval = setInterval(() => {
      this.setState((prev) => ({
        roleIndex: (prev.roleIndex + 1) % ROLE_TITLES.length,
      }));
    }, 3500);
  }

  componentWillUnmount() {
    if (this.roleInterval) {
      clearInterval(this.roleInterval);
    }
  }

  render() {
    const currentRole = ROLE_TITLES[this.state.roleIndex];

    return (
      <div className="home-container">
        <div className="title-container">
          <div className="title">Alexander Zhong</div>

          <div className="typewriter">
            {/* key forces the DOM node to remount so the CSS animation restarts */}
            <h1 key={this.state.roleIndex}>{currentRole}</h1>
          </div>

          <p className="hero-copy">
            I build reliable product systems at Google and experiment with
            practical AI applications, from travel planning tools to machine
            learning and NLP research.
          </p>

          <div className="hero-actions">
            <Link to="/portfolio" className="hero-button hero-button-primary">
              View Work
            </Link>
            <Link to="/aboutme" className="hero-button">
              About Me
            </Link>
          </div>
        </div>

        <div className="new-section">
          <div className="new-heading">What's New</div>
          <div className="new-section-grid">
            <div className="new-section-item">
              <h3 className="card-title">Google Payments</h3>
              <p className="card-description">
                I&apos;m a software engineer in Google Payments, focused on
                Google Wallet, GPay, and Pix reliability and launch work.
              </p>
            </div>

            <div className="new-section-item">
              <h3 className="card-title">Wanderform</h3>
              <p className="card-description">
                I&apos;m building Wanderform, an AI travel planner for
                generating, editing, and saving structured itineraries.
              </p>
            </div>

            <div className="new-section-item">
              <h3 className="card-title">Stanford AI</h3>
              <p className="card-description">
                Recent CS229 and CS224N projects explored Steam popularity
                prediction, GPT-2 adaptation, PEFT, and NLP evaluation.
              </p>
            </div>

            <div className="new-section-item">
              <h3 className="card-title">Music</h3>
              <p className="card-description">
                I&apos;m practicing jazz piano and improvisation while keeping
                up with classical piano and violin.
              </p>
            </div>
          </div>
        </div>
      </div>
    );
  }
}

export default Home;
