import React, { Component } from "react";
import PropTypes from "prop-types";
import "./element.css";
import avodigyPreview from "../assets/img/AvodigyPreview.png";
import scottyPreview from "../assets/img/scottypreview.png";
import ajendaPreview from "../assets/img/AjendaPreview.png";
import netbrainPreview from "../assets/img/NetBrainPreview.png";
import cd39l3Preview from "../assets/img/cd39l3preview.png";
import wanderformPreview from "../assets/img/WanderformPreview.png";
import steamPopularityPreview from "../assets/img/SteamPopularityPreview.png";
import gpt2AdaptationPreview from "../assets/img/GPT2AdaptationPreview.png";
import googlePaymentsPreview from "../assets/img/GooglePaymentsPreview.png";
import comingSoon from "../assets/img/coming_soon.png";

const imgs = {
  "AvodigyPreview.png": avodigyPreview,
  "scottypreview.png": scottyPreview,
  "AjendaPreview.png": ajendaPreview,
  "NetBrainPreview.png": netbrainPreview,
  "cd39l3preview.png": cd39l3Preview,
  "WanderformPreview.png": wanderformPreview,
  "SteamPopularityPreview.png": steamPopularityPreview,
  "GPT2AdaptationPreview.png": gpt2AdaptationPreview,
  "GooglePaymentsPreview.png": googlePaymentsPreview,
};

export class PortfolioElement extends Component {
  getStyle = () => {
    return {};
  };

  getDate(num) {
    var result = "";
    var month = num % 100;
    var year = Math.floor(num / 100);
    if (month < 10) {
      result += "0";
    }
    result = result + month.toString() + "/" + year.toString();
    return result;
  }

  getPreviewImage() {
    return imgs[this.props.info.preview] || comingSoon;
  }

  render() {
    return (
      <div
        className="element-container"
        style={this.getStyle()}
        onClick={this.props.onClick}
      >
        <img id="preview" src={this.getPreviewImage()} alt="" />
        <div className="element-top-row">
          <div className={"type type-" + this.props.info.type}></div>
          <label>{this.getDate(this.props.info.date)}</label>
        </div>
        <h1 id="ele-title">{this.props.info.title}</h1>
        <p id="brief">{this.props.info.brief}</p>
        {/* <hr id="divider" /> */}
        {/* <div id="bottom-info"> */}
        <p id="type">{this.props.info.type}</p>
        {/* <p id="date">{this.getDate(this.props.info.date)}</p> */}
        {/* </div> */}
      </div>
    );
  }
}

// PropTypes
PortfolioElement.propTypes = {
  info: PropTypes.object.isRequired,
};

export default PortfolioElement;
